char* intToRoman(int num) {
    int vals[] = {1000,900,500,400,100,90,50,40,10,9,5,4,1};
    char* syms[] = {"M","CM","D","CD","C","XC","L","XL","X","IX","V","IV","I"};
    char* out = calloc(16, 1);
    for (int i = 0; i < 13; i++)
        while (num >= vals[i]) { strcat(out, syms[i]); num -= vals[i]; }
    return out;
}

